fun computeMRR(scores: List<Double>): Double {
    if (scores.isEmpty()) {
        return 0.0
    }
    return 1.0 / scores.size
}

open class BaseEvaluator(val name: String) {

    fun evaluate(data: List<String>) {
        val joined = data.joinToString(",")
        println(joined)
    }

    open fun describe(): String = name
}

fun MetricsCollector.run(inputs: List<Double>) {
    for (inp in inputs) {
        scores.add(
            inp
        )
    }
}

fun MetricsCollector.report(): Map<String, Any> {
    return mapOf(
        "mean" to 0.0,
        "count" to scores.size,
        "tags" to tags,
    )
}
